import torch
from collections import defaultdict

def compute_activation_norms(model, calibration_loader, n_batches: int = 64) -> dict:
    """
    Compute per-neuron activation L1 norms for FFN intermediate layers.
    Returns dict: {layer_idx: tensor of shape (d_ff,)}
    """
    norms = defaultdict(lambda: None)
    hooks = []

    def make_hook(layer_idx):
        def hook(module, input, output):
            norm = output.detach().abs().mean(dim=(0, 1))   # mean over batch and seq dims
            if norms[layer_idx] is None:
                norms[layer_idx] = norm
            else:
                norms[layer_idx] += norm
        return hook

    # Attach hooks to FFN gate/up activations (after activation function)
    for i, layer in enumerate(model.model.layers):
        h = layer.mlp.act_fn.register_forward_hook(make_hook(i))
        hooks.append(h)

    model.eval()
    with torch.no_grad():
        for batch_idx, batch in enumerate(calibration_loader):
            if batch_idx >= n_batches:
                break
            model(batch["input_ids"].cuda())

    for h in hooks:
        h.remove()

    return {k: v / n_batches for k, v in norms.items()}
